#!/bin/bash
# PERKASA PAINT V2 PRO - ONE-CLICK INSTALLER
# Jalankan sebagai root di Ubuntu 22.04
set -e
echo "=== PERKASA PAINT V2 PRO INSTALLER ==="

echo "[1/6] Buat folder"
mkdir -p /var/www
mkdir -p /root/installer-temp

echo "[2/6] Extract paket V2 PRO dari installer ini..."
cat <<'B64END' | base64 -d > /root/perkasa-paint-v2-pro.tar.gz

B64END

echo "[3/6] Extract tar"
tar -xzf /root/perkasa-paint-v2-pro.tar.gz -C /root/
rm -rf /var/www/perkasa-paint-v2
cp -r /root/perkasa-paint-v2 /var/www/
cd /var/www/perkasa-paint-v2
ls -lh

echo "[4/6] Install Node.js 20, Nginx, SQLite"
apt update -y
curl -fsSL https://deb.nodesource.com/setup_20.x | bash -
apt install -y nodejs nginx sqlite3
npm install -g pm2
node -v
npm -v

echo "[5/6] Install dependencies & Start PM2"
npm install --production
if [ ! -f .env ]; then
  cp .env.example .env
  echo "PORT=3000" >> .env
fi
pm2 delete perkasa-paint || true
pm2 start ecosystem.config.js
pm2 save
pm2 startup || true

echo "[6/6] Setup Nginx"
cat > /etc/nginx/sites-available/perkasa-paint <<'NGINX'
server {
    listen 80;
    server_name _;
    client_max_body_size 20M;
    location / {
        proxy_pass http://localhost:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_cache_bypass $http_upgrade;
        proxy_set_header X-Real-IP $remote_addr;
    }
}
NGINX

ln -sf /etc/nginx/sites-available/perkasa-paint /etc/nginx/sites-enabled/
rm -f /etc/nginx/sites-enabled/default
nginx -t
systemctl restart nginx
systemctl enable nginx

echo ""
echo "=========================================="
echo "✅ PERKASA PAINT V2 PRO ONLINE!"
echo "Buka: http://$(curl -s ifconfig.me || echo IP_VPS)/"
echo "Login: admin / admin123"
echo "DB: /var/www/perkasa-paint-v2/perkasa.db"
echo "Logs: pm2 logs perkasa-paint"
echo "=========================================="
